from string_utils.generation import roman_range

def test_roman_range_negative_start():
    # Test with a negative start value which should raise an error in the baseline.
    try:
        output = list(roman_range(stop=5, start=-1))
        print(f"Output: {output}")
    except ValueError as e:
        print(f"ValueError caught: {str(e)}")

